import { Map, List } from 'immutable';

// Create an immutable Map
const user = Map({ id: 1, name: 'Alice', age: 25 });

// Create an immutable List
const tasks = List(['Learn JS', 'Write code', 'Read docs']);

// Update user age (returns a new Map)
const updatedUser = user.set('age', 26);

console.log(user.get('age')); // 25
console.log(updatedUser.get('age')); // 26

const updatedTasks = tasks.push('Practice Immutable.js');
const updatedUser2 = updatedUser.set('name', 'Alice Smith');

console.log(updatedTasks.toJS()); // ['Learn JS', 'Write code', 'Read docs', 'Practice Immutable.js']
console.log(updatedUser2.toJS()); // { id: 1, name: 'Alice Smith', age: 26 }

const userProfile = Map({
  id: 1,
  name: 'Alice',
  address: Map({ city: 'New York', zip: '10001' }),
  preferences: Map({ theme: 'dark', notifications: true })
});

const updatedProfile = userProfile.setIn(['address', 'city'], 'San Francisco');

console.log(userProfile.getIn(['address', 'city'])); // New York
console.log(updatedProfile.getIn(['address', 'city'])); // San Francisco

const user = {
  name: 'Alice',
  age: 25
};

const handler = {
  set(target, property, value) {
    console.log(`Property '${property}' changed from '${target[property]}' to '${value}'`);
    target[property] = value; // actually update the property
    return true; // indicate success
  }
};

const proxyUser = new Proxy(user, handler);

proxyUser.age = 26; // Logs: Property 'age' changed from '25' to '26'
proxyUser.name = 'Bob'; // Logs: Property 'name' changed from 'Alice' to 'Bob'

function createDeepProxy(target) {
  const handler = {
    set(target, property, value) {
      console.log(`Property '${property}' changed from '${target[property]}' to '${value}'`);
      target[property] = value;
      // Wrap new objects with proxy to track nested changes
      if (value && typeof value === 'object') {
        target[property] = createDeepProxy(value);
      }
      return true;
    }
  };
  // Wrap any existing nested objects
  for (const key in target) {
    if (target[key] && typeof target[key] === 'object') {
      target[key] = createDeepProxy(target[key]);
    }
  }
  return new Proxy(target, handler);
}

const data = {
  user: {
    name: 'Alice',
    details: {
      age: 25
    }
  }
};

const proxyData = createDeepProxy(data);
proxyData.user.details.age = 26; // Logs: Property 'age' changed from '25' to '26'
proxyData.user.name = 'Bob'; // Logs: Property 'name' changed from 'Alice' to 'Bob'

import WebSocket, { WebSocketServer } from 'ws';

const port = 8080;
const wss = new WebSocketServer({ port });

wss.on('connection', (ws: WebSocket) => {
  console.log('New client connected');

  ws.on('message', (data: WebSocket.Data) => {
    // Broadcast the incoming message to all connected clients
    wss.clients.forEach(client => {
      if (client !== ws && client.readyState === WebSocket.OPEN) {
        client.send(data.toString());
      }
    });
  });

  ws.on('close', () => {
    console.log('Client disconnected');
  });
});

console.log(`WebSocket server is running on ws://localhost:${port}`);

const ws = new WebSocket('ws://localhost:8080');

const messagesDiv = document.getElementById('messages') as HTMLDivElement;
const input = document.getElementById('messageInput') as HTMLInputElement;
const sendBtn = document.getElementById('sendBtn') as HTMLButtonElement;

function appendMessage(message: string, isOwnMessage = false) {
  const msgElm = document.createElement('div');
  msgElm.textContent = message;
  msgElm.style.padding = '5px';
  msgElm.style.marginBottom = '5px';
  msgElm.style.backgroundColor = isOwnMessage ? '#DCF8C6' : '#FFFFFF';
  msgElm.style.textAlign = isOwnMessage ? 'right' : 'left';
  messagesDiv.appendChild(msgElm);
  messagesDiv.scrollTop = messagesDiv.scrollHeight;
}

ws.onopen = () => {
  appendMessage('Connected to the chat server.');
};

ws.onmessage = event => {
  appendMessage(event.data);
};

sendBtn.addEventListener('click', () => {
  if (input.value.trim() !== '') {
    ws.send(input.value.trim());
    appendMessage(input.value.trim(), true);
    input.value = '';
  }
});

input.addEventListener('keypress', event => {
  if (event.key === 'Enter') {
    sendBtn.click();
  }
});

function getUserName(user: { name?: string }) {
  // TypeScript infers name might be undefined
  if (!user.name) {
    throw new Error("User name is missing");
  }
  return user.name;
}

type Result<T> = { success: true; value: T } | { success: false; error: string };

function parseJson<T>(json: string): Result<T> {
  try {
    const parsed = JSON.parse(json) as T;
    return { success: true, value: parsed };
  } catch (e) {
    return { success: false, error: (e as Error).message };
  }
}

const result = parseJson<{ name: string }>(`{"name":"Alice"}`);

if (!result.success) {
  // TypeScript infers this is the error case
  console.error("Parsing failed:", result.error);
} else {
  // TypeScript infers the value is correctly typed
  console.log("Parsed name:", result.value.name);
}

type InferError<T> = T extends (...args: any[]) => Promise<infer R>
  ? R extends { success: false; error: infer E }
    ? E
    : never
  : never;

async function fetchUser(): Promise<Result<{ id: number; name: string }>> {
  // Example fetching user
  return { success: true, value: { id: 1, name: "Alice" } };
}

// TypeScript infers the error type as string
type FetchUserError = InferError<typeof fetchUser>;

