-- Instead of this:
CREATE TABLE Vehicles (
    VehicleID INT PRIMARY KEY,
    Make VARCHAR(50),
    Model VARCHAR(50),
    EngineSize VARCHAR(20), -- for cars only
    NumberOfSeats INT         -- for buses only
);

-- Use this approach:
CREATE TABLE Vehicles (
    VehicleID INT PRIMARY KEY,
    Make VARCHAR(50),
    Model VARCHAR(50)
);

CREATE TABLE CarDetails (
    VehicleID INT PRIMARY KEY,
    EngineSize VARCHAR(20),
    FOREIGN KEY (VehicleID) REFERENCES Vehicles(VehicleID)
);

CREATE TABLE BusDetails (
    VehicleID INT PRIMARY KEY,
    NumberOfSeats INT,
    FOREIGN KEY (VehicleID) REFERENCES Vehicles(VehicleID)
);
